import{_ as t,o as s,c as a,a2 as n}from"./chunks/framework.y1bVONfd.js";const u=JSON.parse('{"title":"Optimization Features","description":"wr-proxy request optimization — token compression, session compression, and dynamic content reordering","frontmatter":{"title":"Optimization Features","description":"wr-proxy request optimization — token compression, session compression, and dynamic content reordering"},"headers":[],"relativePath":"guide/optimization.md","filePath":"guide/optimization.md"}'),o={name:"guide/optimization.md"};function i(r,e,p,l,d,c){return s(),a("div",null,[...e[0]||(e[0]=[n(`<h1 id="optimization-features" tabindex="-1">Optimization Features <a class="header-anchor" href="#optimization-features" aria-label="Permalink to &quot;Optimization Features&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>wr-proxy includes built-in request optimization features that transform outgoing requests before they reach upstream providers — reducing token costs, improving cache hit rates, and handling long conversations gracefully.</p><p>All features are controlled via system settings and can be toggled independently without restarting wr-proxy.</p><h2 id="feature-toggles" tabindex="-1">Feature Toggles <a class="header-anchor" href="#feature-toggles" aria-label="Permalink to &quot;Feature Toggles&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Setting Key</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td>Dynamic Content Reordering</td><td><code>feature_dynamic_content_last</code></td><td>off</td><td>Move dynamic content to end of context</td></tr><tr><td>Token Compression</td><td><code>feature_token_compression</code></td><td>off</td><td>Compress long system prompts</td></tr><tr><td>Session Compression</td><td><code>feature_session_compression</code></td><td>off</td><td>Summarize long conversation history</td></tr></tbody></table><p>Toggle via <strong>Settings</strong> in the admin panel or <code>PUT /api/settings</code>.</p><h2 id="_1-dynamic-content-reordering" tabindex="-1">1. Dynamic Content Reordering <a class="header-anchor" href="#_1-dynamic-content-reordering" aria-label="Permalink to &quot;1. Dynamic Content Reordering&quot;">​</a></h2><h3 id="problem" tabindex="-1">Problem <a class="header-anchor" href="#problem" aria-label="Permalink to &quot;Problem&quot;">​</a></h3><p>When dynamic content (URLs, timestamps, hash values) appears early in the conversation, it prevents upstream prompt caching from working effectively. Each request looks &quot;different&quot; even when the core instruction hasn&#39;t changed.</p><h3 id="solution" tabindex="-1">Solution <a class="header-anchor" href="#solution" aria-label="Permalink to &quot;Solution&quot;">​</a></h3><p>wr-proxy detects messages containing dynamic patterns and reorders them within their role group — pushing dynamic messages to the end:</p><table tabindex="0"><thead><tr><th>Pattern</th><th>Example</th></tr></thead><tbody><tr><td>URLs</td><td><code>https://api.example.com/v1/...</code></td></tr><tr><td>Dates</td><td><code>2026-06-07</code></td></tr><tr><td>Times</td><td><code>14:30:00</code></td></tr><tr><td>Hashes/UUIDs</td><td><code>a1b2c3d4e5f6...</code></td></tr><tr><td>Long numbers</td><td><code>1234567890123</code></td></tr></tbody></table><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Before:                          After:</span></span>
<span class="line"><span>[system: &quot;You are...&quot;]           [system: &quot;You are...&quot;]</span></span>
<span class="line"><span>[user: &quot;Check https://...&quot;]      [user: &quot;What&#39;s the status?&quot;]</span></span>
<span class="line"><span>[user: &quot;What&#39;s the status?&quot;]     [user: &quot;Check https://...&quot;]  ← moved to end</span></span></code></pre></div><p>Result: the static prefix stays cacheable upstream.</p><h2 id="_2-token-compression-rtk" tabindex="-1">2. Token Compression (RTK) <a class="header-anchor" href="#_2-token-compression-rtk" aria-label="Permalink to &quot;2. Token Compression (RTK)&quot;">​</a></h2><h3 id="problem-1" tabindex="-1">Problem <a class="header-anchor" href="#problem-1" aria-label="Permalink to &quot;Problem&quot;">​</a></h3><p>Long system prompts (2000+ characters) consume tokens on every request, even though the instruction rarely changes.</p><h3 id="solution-1" tabindex="-1">Solution <a class="header-anchor" href="#solution-1" aria-label="Permalink to &quot;Solution&quot;">​</a></h3><p>When enabled, system prompts exceeding the threshold are compressed in-place:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Original (3000 chars):</span></span>
<span class="line"><span>&quot;You are an expert code reviewer. Follow these guidelines:</span></span>
<span class="line"><span> 1. Check for security vulnerabilities...</span></span>
<span class="line"><span> 2. Verify error handling...</span></span>
<span class="line"><span> ... (2000 more characters) ...</span></span>
<span class="line"><span> 99. Ensure consistent naming...&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Compressed:</span></span>
<span class="line"><span>&quot;You are an expert code reviewer. Follow these guidelines:</span></span>
<span class="line"><span> 1. Check for security vulnerabilities...</span></span>
<span class="line"><span> 2. Verify error handling...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[... 2300 characters omitted ...]</span></span>
<span class="line"><span></span></span>
<span class="line"><span> 98. Use type hints consistently.</span></span>
<span class="line"><span> 99. Ensure consistent naming.&quot;</span></span></code></pre></div><p>The model receives a compact representation while preserving the critical first and last instructions.</p><h2 id="_3-session-compression" tabindex="-1">3. Session Compression <a class="header-anchor" href="#_3-session-compression" aria-label="Permalink to &quot;3. Session Compression&quot;">​</a></h2><h3 id="problem-2" tabindex="-1">Problem <a class="header-anchor" href="#problem-2" aria-label="Permalink to &quot;Problem&quot;">​</a></h3><p>Long conversations (10+ turns) accumulate significant token costs. Early messages may be irrelevant to the current topic.</p><h3 id="solution-2" tabindex="-1">Solution <a class="header-anchor" href="#solution-2" aria-label="Permalink to &quot;Solution&quot;">​</a></h3><p>When a conversation exceeds the compression threshold, wr-proxy:</p><ol><li>Preserves the most recent 5 turns intact</li><li>Summarizes earlier turns into a concise system message</li><li>Injects the summary before the recent messages</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Before (15 turns):                 After:</span></span>
<span class="line"><span>[system: &quot;You are...&quot;]             [system: &quot;You are...&quot;]</span></span>
<span class="line"><span>[turn 1: user/assistant]           [system: &quot;[Summary of turns 1-10]</span></span>
<span class="line"><span>[turn 2: user/assistant]            共 10 轮对话，约 5000 字符。</span></span>
<span class="line"><span> ...                               主要话题：部署流程、数据库配置...&quot;]</span></span>
<span class="line"><span>[turn 10: user/assistant]          [turn 11: user/assistant]  ← preserved</span></span>
<span class="line"><span>[turn 11: user/assistant]          [turn 12: user/assistant]</span></span>
<span class="line"><span> ...                               ...</span></span>
<span class="line"><span>[turn 15: user/assistant]          [turn 15: user/assistant]</span></span></code></pre></div><h2 id="session-context-awareness" tabindex="-1">Session Context Awareness <a class="header-anchor" href="#session-context-awareness" aria-label="Permalink to &quot;Session Context Awareness&quot;">​</a></h2><p>Beyond the three toggleable features, wr-proxy&#39;s smart model selection also considers session context:</p><ul><li><strong>Large context</strong> (&gt;16K tokens accumulated): complexity score +0.15, may trigger premium model selection</li><li><strong>Medium context</strong> (&gt;8K tokens): complexity score +0.08</li></ul><p>This ensures that as conversations grow deeper, the model selection adapts accordingly.</p><h2 id="api-compatibility" tabindex="-1">API Compatibility <a class="header-anchor" href="#api-compatibility" aria-label="Permalink to &quot;API Compatibility&quot;">​</a></h2><p>All three optimization features also support Anthropic (<code>/v1/messages</code>) and Cohere (<code>/v1/chat</code>) API formats through format translation before optimization is applied.</p><h2 id="admin-endpoints" tabindex="-1">Admin Endpoints <a class="header-anchor" href="#admin-endpoints" aria-label="Permalink to &quot;Admin Endpoints&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Endpoint</th><th>Description</th></tr></thead><tbody><tr><td><code>GET /admin/features</code></td><td>View current feature toggle states</td></tr><tr><td><code>POST /admin/features</code></td><td>Reload feature toggles from DB</td></tr><tr><td><code>POST /admin/conversation_compress</code></td><td>Manually trigger conversation compression</td></tr></tbody></table>`,37)])])}const m=t(o,[["render",i]]);export{u as __pageData,m as default};
